using Asp.Versioning;using Fixar.Application.Common.Interfaces;using Fixar.Application.Common.Models;using Fixar.Infrastructure.Identity;using Microsoft.AspNetCore.Authorization;using Microsoft.AspNetCore.Mvc;
namespace Fixar.API.Controllers;
[ApiController,ApiVersion("1.0"),Route("api/v{version:apiVersion}/cash-flow"),Authorize(Policy=AuthorizationPolicies.CanViewCashFlow)]public class CashFlowController(IFinancialCashFlowService service):ControllerBase
{[HttpGet("balances")]public async Task<IActionResult>Balances(CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await service.GetBalancesAsync(ct)));[HttpGet("daily")]public async Task<IActionResult>Daily(DateTime? dateFrom,DateTime? dateTo,string? currency,CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await service.GetDailyCashFlowAsync(dateFrom??DateTime.UtcNow.Date.AddDays(-30),(dateTo??DateTime.UtcNow).Date.AddDays(1),currency,ct)));[HttpGet("monthly")]public async Task<IActionResult>Monthly(DateTime? dateFrom,DateTime? dateTo,string? currency,CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await service.GetMonthlyCashFlowAsync(dateFrom??DateTime.UtcNow.Date.AddMonths(-12),(dateTo??DateTime.UtcNow).Date.AddDays(1),currency,ct)));[HttpGet("payment-methods")]public async Task<IActionResult>Methods(DateTime? dateFrom,DateTime? dateTo,CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await service.GetPaymentMethodBreakdownAsync(dateFrom??DateTime.UtcNow.Date.AddDays(-30),(dateTo??DateTime.UtcNow).Date.AddDays(1),ct)));[HttpGet("liquidity")]public async Task<IActionResult>Liquidity(CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await service.GetLiquiditySummaryAsync(ct)));[HttpGet("cheque-maturity")]public async Task<IActionResult>Maturity(CancellationToken ct)=>Ok(ApiResponse<object>.SuccessResponse(await service.GetChequeMaturityAsync(ct)));}
